// Input is already one job per item
const jobs = items.map(i => i.json);

const blacklist = [
  'software developer',
  'software engineer',
  'frontend',
  'backend',
  'full stack',
  'trainee',
  'coding'
];

const whitelist = [
  'database administrator',
  'dba',
  'sql server',
  'mysql',
  'sybase',
  'ase',
  'replication',
  'performance tuning'
];

const filtered = jobs.filter(job => {
  const title = (job.title || '').toLowerCase();
  const body  = (job.description || '').toLowerCase();
  const fullText = `${title} ${body}`;

  const hasDBA = whitelist.some(w => fullText.includes(w));

  // 🔒 Only kill if title CLEARLY indicates dev role
  const isDevTitle = blacklist.some(b => title.includes(b));

  return hasDBA && !isDevTitle;
});

// Return as n8n items
return filtered.map(job => ({ json: job }));

return items.map(item => {
  const job = item.json;

  // Detect contract from text (critical fix)
  const desc = (job.description || '').toLowerCase();
  const title = (job.title || '').toLowerCase();

  const isDailyRate =
    /per day|\/day|daily rate|inside ir35|outside ir35/i.test(desc);

  const isContract =
    job.contract_type === 'contract' ||
    job.contract_time === 'contract' ||
    isDailyRate;

  const isPermanent =
    !isContract &&
    (job.contract_time === 'full_time' || job.contract_type === 'permanent');

  return {
    json: {
      // Stable identifiers
      job_id: job.id || null,
      source: 'Adzuna',

      // Core job info
      title: job.title || '',
      company: job.company?.display_name || '',
      location: job.location?.display_name || '',

      // DBA-critical content
      job_description: job.description || '',

      // Apply path
      apply_url: job.redirect_url || '',

      // Compensation
      salary_min: job.salary_min || null,
      salary_max: job.salary_max || null,
      salary_is_estimated: job.salary_is_predicted || false,

      // Job metadata (preserve raw values)
      contract_type: job.contract_type || job.contract_time || null,
      employment_type: job.contract_time || null,
      posted_at: job.created || null,
      category: job.category?.tag || null,

      // ✅ Derived helpers (FIXED)
      is_contract: isContract,
      is_permanent: isPermanent,

      // Text block for LLM (DO NOT CHANGE STRUCTURE)
      llm_input: `
Job Title:
${job.title || 'N/A'}

Company:
${job.company?.display_name || 'N/A'}

Location:
${job.location?.display_name || 'N/A'}

Contract Type:
${job.contract_type || job.contract_time || 'N/A'}

Salary:
${job.salary_min || 'N/A'} – ${job.salary_max || 'N/A'}

Job Description:
${job.description || 'N/A'}
`.trim()
    }
  };
});

const raw = (item.json.text || '').trim();
const originalJob = $('Wait – Rate Limit').item.json;

let parsed;
try {
  const cleanJson = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  return {
    json: {
      ...originalJob,
      score: 0,
      role_type: 'NOT_DBA',
      recommendation: 'SKIP',
      reason: 'LLM Error: Failed to parse response JSON.'
    }
  };
}

const score = parsed.score || 0;

// Enforce recommendation based on score thresholds — overrides LLM decision
let recommendation;
if (score >= 70) {
  recommendation = 'APPLY';
} else if (score >= 50) {
  recommendation = 'MAYBE';
} else {
  recommendation = 'SKIP';
}

return {
  json: {
    ...originalJob,
    score,
    role_type: parsed.role_type || 'NOT_DBA',
    recommendation,
    reason: parsed.reason || 'Missing reason in LLM response.'
  }
};

const newJobs = $("Normalize – DBA Job for LLM").all();

// Safely load history — empty sheet returns 0 items
let sentHistory = [];
try {
  sentHistory = $("Load Sent Job History").all();
  // If the sheet is empty, Google Sheets node may return items without a job_id column
  // Filter to only items that actually look like history records
  sentHistory = sentHistory.filter(item => item.json.job_id);
} catch(e) {
  sentHistory = [];
}

// Build sets from history: by job_id AND by normalised company+title (catches re-posts with new IDs)
const sentIds = new Set(sentHistory.map(item => String(item.json.job_id).trim()));
const sentTitleKeys = new Set(
  sentHistory.map(item => {
    const title = (item.json.title || '').toLowerCase().trim();
    const company = (item.json.company || '').toLowerCase().trim();
    return `${company}||${title}`;
  })
);

// Deduplicate within this run too (Berkshire + London searches may return the same job)
const seen = new Set();
const result = [];
for (const item of newJobs) {
  const id = String(item.json.job_id || '').trim();
  const titleKey = `${(item.json.company || '').toLowerCase().trim()}||${(item.json.title || '').toLowerCase().trim()}`;

  if (!sentIds.has(id) && !sentTitleKeys.has(titleKey) && !seen.has(id)) {
    seen.add(id);
    result.push(item);
  }
}
return result;

// Current job item 
const job = $('Parse LLM Result').item.json;

// Safe helper
const safe = (v) => (v === undefined || v === null || v === '' ? 'N/A' : v);

// Description handling
const desc = job.job_description || '';
const shortDesc =
  desc.length > 2000
    ? desc.slice(0, 2000).replace(/\n/g, '<br>') +
      '<br><br><em>[Description truncated]</em>'
    : desc.replace(/\n/g, '<br>');

// Subject
const subject = `[DBA Job Match v3.0 – ${safe(job.score)}] ${safe(job.title)} – ${safe(job.company)}`;

return {
  json: {
    to: 'edwardtong@gmail.com',
    subject,
    html: `
<div style="font-family: Arial, Helvetica, sans-serif; font-size: 14px; color: #222;">

  <h2 style="margin-bottom: 4px;">${safe(job.title)}</h2>

  <p style="margin-top: 0; color: #555;">
    <strong>${safe(job.company)}</strong> · ${safe(job.location)}
  </p>

  <hr>

  <table cellpadding="6" cellspacing="0">
    <tr><td><strong>Score</strong></td><td>${safe(job.score)}</td></tr>
    <tr><td><strong>Recommendation</strong></td><td>${safe(job.recommendation)}</td></tr>
    <tr><td><strong>Reason</strong></td><td>${safe(job.reason)}</td></tr>
    <tr><td><strong>Salary</strong></td>
        <td>£${safe(job.salary_min)} – £${safe(job.salary_max)}</td></tr>
    <tr><td><strong>Contract</strong></td><td>${safe(job.contract_type)}</td></tr>
  </table>

  <p style="margin:16px 0;">
    <a href="${safe(job.apply_url)}"
       style="background:#1a73e8;color:#fff;padding:10px 16px;
              text-decoration:none;border-radius:4px;font-weight:bold;">
      Apply for this job →
    </a>
  </p>

  <hr>

  <h3>Job Description</h3>
  <p style="line-height:1.5;">${shortDesc || '<em>No description provided</em>'}</p>

  <hr>

  <p style="font-size:12px;color:#777;">
    Sent automatically by n8n · Source: ${safe(job.source)}
  </p>

</div>
`.trim()
  }
};

const seen = new Set();
const output = [];

for (const item of items) {
  const job = item.json;

  // Primary key: Adzuna job ID
  let key = job.id;

  // Fallback if ID is missing (rare)
  if (!key) {
    key = [
      job.title || '',
      job.company?.display_name || '',
      job.location?.display_name || ''
    ].join('|').toLowerCase();
  }

  // Deduplicate
  if (!seen.has(key)) {
    seen.add(key);
    output.push({ json: job });
  }
}

return output;

